<section class="cart-page"><header><span class="eyebrow">Daftar pilihan</span><h1>Keranjang</h1><?php if($items):?><p class="cart-help">Ubah jumlah produk, lalu tekan <strong>Perbarui keranjang</strong>. Gunakan tombol hapus untuk mengeluarkan produk.</p><?php endif?></header><?php if($items):?><form method="post" action="<?=url('/keranjang')?>" id="cart-update-form"><?=csrf_field()?><input type="hidden" name="_method" value="PUT"><div class="cart-list"><?php $total=0;foreach($items as $x):$total+=$x['total'];?><article><div class="cart-item-copy"><strong><a href="<?=url('/produk/'.$x['slug'])?>"><?=e($x['name'])?></a></strong><span><?=e($x['variant_name'])?> · <?=money($x['pricing']['final'])?> per item</span></div><label class="cart-quantity">Jumlah<span class="sr-only"> <?=e($x['name'].' '.$x['variant_name'])?></span><input type="number" inputmode="numeric" name="quantity[<?=$x['variant_id']?>]" min="1" max="<?=$x['stock_qty']?>" value="<?=$x['quantity']?>" data-cart-quantity></label><small class="cart-stock">Stok tersedia: <?=$x['stock_qty']?></small><b class="cart-line-total"><?=money($x['total'])?></b><button type="submit" class="remove-button" form="remove-<?=$x['variant_id']?>" aria-label="Hapus <?=e($x['name'].' '.$x['variant_name'])?> dari keranjang">Hapus</button></article><?php endforeach?></div><p class="cart-change-note" id="cart-change-note" aria-live="polite"></p><div class="cart-summary"><span>Subtotal <strong><?=money($total)?></strong><small>Biaya pengiriman dihitung saat checkout.</small></span><div><button class="secondary-button" type="submit">Perbarui keranjang</button><a class="button" href="<?=url('/checkout')?>">Lanjut ke checkout</a></div></div></form><?php foreach($items as $x):?><form id="remove-<?=$x['variant_id']?>" method="post" action="<?=url('/keranjang/'.$x['variant_id'])?>" onsubmit="return confirm('Hapus produk ini dari keranjang?')"><?=csrf_field()?><input type="hidden" name="_method" value="DELETE"></form><?php endforeach?><?php else:?><div class="empty-state"><h2>Keranjang masih kosong</h2><p>Jelajahi produk dan pilih varian yang Anda inginkan.</p><a class="button" href="<?=url('/produk')?>">Lihat semua produk</a></div><?php endif?></section><script>document.querySelectorAll('[data-cart-quantity]').forEach(input=>input.addEventListener('input',()=>document.querySelector('#cart-change-note').textContent='Jumlah berubah. Tekan Perbarui keranjang untuk menghitung ulang subtotal.'));</script>
